        let _options = try conversionOptionsFromJson("{\"strip_tags\":[\"div\",\"span\"]}")
        let result = try convert("<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("Inside div"), "expected to contain: \("Inside div")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("span text"), "expected to contain: \("span text")")
    }

    func testOptionsStrongEmUnderscore() throws {
        // Strong and em tags use underscore symbol instead of asterisk
        let _options = try conversionOptionsFromJson("{\"strong_em_symbol\":\"_\"}")
        let result = try convert("<p><strong>bold</strong> and <em>italic</em></p>", _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("__bold__"), "expected to contain: \("__bold__")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("_italic_"), "expected to contain: \("_italic_")")
    }

    func testOptionsSubSymbolTilde() throws {
        // Subscript rendered with tilde symbol
        let _options = try conversionOptionsFromJson("{\"sub_symbol\":\"~\"}")
        let result = try convert("<p>H<sub>2</sub>O</p>", _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("~2~"), "expected to contain: \("~2~")")
    }

    func testOptionsSupSymbolCaret() throws {
        // Superscript rendered with caret symbol
        let _options = try conversionOptionsFromJson("{\"sup_symbol\":\"^\"}")
        let result = try convert("<p>x<sup>2</sup></p>", _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("^2^"), "expected to contain: \("^2^")")
    }

    func testOptionsWhitespaceNormalized() throws {
        // Normalized whitespace mode collapses multiple spaces
        let _options = try conversionOptionsFromJson("{\"whitespace_mode\":\"Normalized\"}")
        let result = try convert("<p>Text   with    extra   spaces.</p>", _options)
        XCTAssertNotNil(result.content(), "expected non-nil value")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("Text"), "expected to contain: \("Text")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("with"), "expected to contain: \("with")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("extra"), "expected to contain: \("extra")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("spaces."), "expected to contain: \("spaces.")")
    }

    func testOptionsWhitespaceStrict() throws {
        // Strict whitespace mode preserves whitespace as-is
        let _options = try conversionOptionsFromJson("{\"whitespace_mode\":\"Strict\"}")
        let result = try convert("<p>Preserved   spacing.</p>", _options)
        XCTAssertNotNil(result.content(), "expected non-nil value")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("Preserved"), "expected to contain: \("Preserved")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("spacing."), "expected to contain: \("spacing.")")
    }

    func testOptionsWrapDisabled() throws {
        // Wrap option disabled preserves long lines without breaking
        let _options = try conversionOptionsFromJson("{\"wrap\":false}")
        let result = try convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("This is a long paragraph that should not be wrapped at all because wrapping is disabled."), "expected to contain: \("This is a long paragraph that should not be wrapped at all because wrapping is disabled.")")
    }

    func testOptionsWrapEnabled() throws {
        // Wrap option enabled with custom width wraps long lines
        let _options = try conversionOptionsFromJson("{\"wrap\":true,\"wrap_width\":40}")
        let result = try convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", _options)
        XCTAssertNotNil(result.content(), "expected non-nil value")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("This is a long paragraph"), "expected to contain: \("This is a long paragraph")")
    }

}
